{
  "name": "CJBS Vibe Coding Workshop",
  "description": "An interactive learning platform for Cambridge Judge Business School MBA students to explore Vibe Coding using Google AI Studio and Lovable."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface VibeResponse {
  colorPalette: string[];
  fontPairing: string;
  layoutStyle: string;
  reasoning: string;
  uiElementName: string;
}

export interface CurriculumModule {
  id: string;
  title: string;
  description: string;
  icon: string;
  duration: string;
}

export enum AppState {
  HOME = 'HOME',
  LAB = 'LAB',
  CURRICULUM = 'CURRICULUM',
  TOOLS = 'TOOLS'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { VibeResponse } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const vibeSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    colorPalette: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "An array of 3-5 hex color codes that match the user's requested vibe.",
    },
    fontPairing: {
      type: Type.STRING,
      description: "A description of a font pairing (e.g., 'Playfair Display for headers, Lato for body') that matches the vibe.",
    },
    layoutStyle: {
      type: Type.STRING,
      description: "A short description of the layout style (e.g., 'Minimalist single column', 'Bento box grid').",
    },
    reasoning: {
      type: Type.STRING,
      description: "A brief explanation (max 2 sentences) of why these choices match the requested vibe.",
    },
    uiElementName: {
      type: Type.STRING,
      description: "A creative name for a UI component that would fit this vibe (e.g., 'Zen Mode Dashboard', 'High-Frequency Trading Blotter')."
    }
  },
  required: ["colorPalette", "fontPairing", "layoutStyle", "reasoning", "uiElementName"],
};

export const generateVibeConfig = async (userVibe: string): Promise<VibeResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview",
      contents: `You are an expert UI/UX designer and 'Vibe Coder'.
      Analyze the following 'vibe' description provided by a user and generate a design system specification.

      User Vibe: "${userVibe}"

      Return a JSON object describing the visual identity.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: vibeSchema,
        systemInstruction: "You are a creative technical partner for MBA students learning to code with AI. Be inspiring yet precise.",
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as VibeResponse;
    }
    throw new Error("No response text generated");
  } catch (error) {
    console.error("Gemini Vibe Check Failed:", error);
    // Fallback for demo purposes if API fails or key is missing
    return {
      colorPalette: ["#FF5733", "#C70039", "#900C3F", "#581845"],
      fontPairing: "Roboto & Open Sans (Fallback)",
      layoutStyle: "Standard Grid",
      reasoning: "We couldn't connect to the AI brain right now, so here is a default energetic palette.",
      uiElementName: "Emergency Fallback Component"
    };
  }
};

import React, { useState } from 'react';
import { generateVibeConfig } from '../services/gemini';
import { VibeResponse } from '../types';
import { Sparkles, Loader2, ArrowRight, Paintbrush } from 'lucide-react';

const VibeLab: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<VibeResponse | null>(null);

  const handleVibeCheck = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    try {
      const data = await generateVibeConfig(prompt);
      setResult(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="w-full max-w-5xl mx-auto p-4 md:p-8">
      <div className="text-center mb-12">
        <h2 className="text-3xl md:text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-ai-cyan to-ai-purple mb-4">
          The Vibe Lab
        </h2>
        <p className="text-gray-300 max-w-2xl mx-auto">
          Experience how "Vibe Coding" works. You describe the feeling or business intent, and the AI translates it into technical design decisions.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Input Section */}
        <div className="glass-panel p-8 rounded-2xl flex flex-col justify-center min-h-[400px]">
          <label className="block text-sm font-medium text-ai-cyan mb-2">
            Describe your App's Vibe
          </label>
          <textarea
            className="w-full bg-cjbs-dark/50 border border-gray-700 rounded-xl p-4 text-white placeholder-gray-500 focus:ring-2 focus:ring-ai-purple focus:border-transparent outline-none transition-all resize-none h-40"
            placeholder="e.g., 'A meditation app for busy CEOs that feels like a quiet Japanese garden' or 'A high-energy crypto trading dashboard for Gen Z'"
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
          />

          <div className="mt-6 flex justify-end">
            <button
              onClick={handleVibeCheck}
              disabled={loading || !prompt}
              className={`flex items-center gap-2 px-6 py-3 rounded-xl font-semibold transition-all ${
                loading || !prompt
                  ? 'bg-gray-700 text-gray-400 cursor-not-allowed'
                  : 'bg-gradient-to-r from-ai-purple to-ai-cyan text-white hover:scale-105 shadow-lg shadow-ai-purple/25'
              }`}
            >
              {loading ? (
                <>
                  <Loader2 className="animate-spin w-5 h-5" />
                  Generating Specs...
                </>
              ) : (
                <>
                  <Sparkles className="w-5 h-5" />
                  Translate Vibe to Code
                </>
              )}
            </button>
          </div>

          <div className="mt-8 text-xs text-gray-500">
            <p className="font-semibold text-gray-400 mb-1">Try these:</p>
            <div className="flex flex-wrap gap-2">
              <span onClick={() => setPrompt("Minimalist luxury fashion brand based in Paris")} className="cursor-pointer hover:text-ai-cyan bg-white/5 px-2 py-1 rounded-md">Luxury Fashion</span>
              <span onClick={() => setPrompt("Cyberpunk arcade game interface")} className="cursor-pointer hover:text-ai-cyan bg-white/5 px-2 py-1 rounded-md">Cyberpunk</span>
              <span onClick={() => setPrompt("Trustworthy medical portal for elderly patients")} className="cursor-pointer hover:text-ai-cyan bg-white/5 px-2 py-1 rounded-md">Medical Portal</span>
            </div>
          </div>
        </div>

        {/* Output Section */}
        <div className="relative min-h-[400px]">
          {result ? (
            <div className="glass-panel p-8 rounded-2xl h-full animate-pulse-slow border-ai-cyan/30 flex flex-col justify-between">
              <div>
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-xl font-bold text-white flex items-center gap-2">
                    <Paintbrush className="w-5 h-5 text-ai-cyan" />
                    AI Design System
                  </h3>
                  <span className="text-xs font-mono bg-ai-purple/20 text-ai-purple px-2 py-1 rounded">
                    JSON_OUTPUT_RECEIVED
                  </span>
                </div>

                <div className="space-y-6">
                  <div>
                    <h4 className="text-sm text-gray-400 uppercase tracking-wider mb-2">Component Name</h4>
                    <p className="text-lg font-serif text-white">{result.uiElementName}</p>
                  </div>

                  <div>
                    <h4 className="text-sm text-gray-400 uppercase tracking-wider mb-2">AI Reasoning</h4>
                    <p className="text-gray-300 text-sm leading-relaxed italic border-l-2 border-ai-purple pl-4">
                      "{result.reasoning}"
                    </p>
                  </div>

                  <div>
                    <h4 className="text-sm text-gray-400 uppercase tracking-wider mb-2">Color Palette</h4>
                    <div className="flex gap-4">
                      {result.colorPalette.map((color, idx) => (
                        <div key={idx} className="group relative">
                          <div 
                            className="w-12 h-12 rounded-full shadow-lg border border-white/10 transition-transform hover:scale-110 cursor-pointer"
                            style={{ backgroundColor: color }}
                          />
                          <span className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[10px] font-mono opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                            {color}
                          </span>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                     <div>
                        <h4 className="text-sm text-gray-400 uppercase tracking-wider mb-1">Typography</h4>
                        <p className="text-white text-sm">{result.fontPairing}</p>
                     </div>
                     <div>
                        <h4 className="text-sm text-gray-400 uppercase tracking-wider mb-1">Layout</h4>
                        <p className="text-white text-sm">{result.layoutStyle}</p>
                     </div>
                  </div>
                </div>
              </div>

              <div className="mt-8 pt-6 border-t border-white/10 text-center">
                 <p className="text-sm text-gray-400 mb-2">Ready to build this?</p>
                 <button className="text-ai-cyan hover:text-white font-semibold flex items-center justify-center gap-2 mx-auto transition-colors">
                    Export to Google AI Studio <ArrowRight className="w-4 h-4" />
                 </button>
              </div>
            </div>
          ) : (
            <div className="glass-panel p-8 rounded-2xl h-full flex flex-col items-center justify-center text-center border-dashed border-2 border-gray-700">
               <div className="w-16 h-16 bg-gray-800 rounded-full flex items-center justify-center mb-4">
                  <Sparkles className="w-8 h-8 text-gray-500" />
               </div>
               <h3 className="text-xl font-semibold text-gray-400 mb-2">Awaiting Vibe Input</h3>
               <p className="text-gray-500 text-sm max-w-xs">
                 Enter a prompt on the left to see how Generative AI translates abstract concepts into concrete design specs.
               </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

